**Example Code**

Here's an example of using the Libgcrypt library for file system encryption in C:
```c
#include <gcrypt.h>

int main() {
    // Initialize the Libgcrypt library
    gcry_control(GCRYCTL_SET_SEED, 0);

    // Create a cipher context
    gcry_cipher_hd_t cipher;
    gcry_cipher_open(&cipher, GCRY_CIPHER_AES256, GCRY_CIPHER_MODE_GCM, 0);

    // Encrypt a file
    FILE *file = fopen("file.txt", "rb");
    if (file == NULL) {
        return 1;
    }

    // Read the file contents
    char *contents = malloc(1024);
    size_t size = fread(contents, 1, 1024, file);

    // Encrypt the contents
    gcry_cipher_encrypt(cipher, contents, size);

    // Write the encrypted contents to a new file
    FILE *encrypted_file = fopen("encrypted_file.txt", "wb");
    if (encrypted_file == NULL) {
        return 1;
    }

    fwrite(contents, 1, size, encrypted_file);

    // Close the files
    fclose(file);
    fclose(encrypted_file);

    // Clean up
    gcry_cipher_close(cipher);
    free(contents);

    return 0;
}
```
